INSERT INTO public.standard_terms (id, title, body, sort_order, is_active, created_at) VALUES
  ('58008289-ac4e-4508-9048-6d56a37b8497', 'Purchasing Additional Gear (Tiered Discount)', 'Players may purchase additional Cooper Cricket equipment outside of their allocated sponsorship package at their designated tier discount rate.', 1, true, '2026-03-05T13:50:34.727872+00:00'),
  ('db9b7c83-bc9e-4349-ac46-3100b9f442ce', 'Early Termination and Exit Fee', 'If the player wishes to terminate this contract before the agreed end date, they must provide 30 days written notice and pay an early exit fee to Cooper Cricket.', 2, true, '2026-03-05T13:50:34.727872+00:00'),
  ('de9609ea-fdd4-4fd7-925e-950d107feb59', 'Non-Supplied Specialist Equipment Exception', 'The player must wear Cooper Cricket branding for all equipment categories we supply. If the player requires a specialist item that Cooper Cricket does not currently manufacture, they are permitted to use an alternative brand.', 3, true, '2026-03-05T13:50:34.727872+00:00'),
  ('46b206a0-b1d4-475d-862b-6dbcb3982d7d', 'Alternative Bat Branding (Sticker Application)', 'While Cooper Cricket prefers players to use our custom crafted bats, we are willing to supply branding decals for an alternative bat of the player''s choosing.', 4, true, '2026-03-05T13:50:34.727872+00:00'),
  ('36351dad-5663-4eac-820c-446c51a19771', 'Workshop Repairs and Refurbishments', 'Equipment repairs and refurbishments are provided free of charge for fully sponsored players. For tiered agreements, repairs are charged at the designated discount rate.', 5, true, '2026-03-05T13:50:34.727872+00:00'),
  ('48d0a758-0965-4edb-9ca3-ca0d0f55ede4', 'Branded Equipment Requirement', 'Player must wear Cooper Cricket branded equipment during all official matches, training sessions, and public appearances related to cricket.', 6, true, '2026-03-05T13:50:34.727872+00:00'),
  ('90239261-4f1d-463f-95c5-e639ecef4a84', 'Equipment Ownership', 'All equipment provided remains the property of Cooper Cricket and must be returned upon termination of this agreement.', 7, true, '2026-03-05T13:50:34.727872+00:00'),
  ('f47f7d4a-26db-416f-9217-504494805798', 'Exclusivity', 'Player agrees not to endorse or publicly use competing cricket equipment brands during the term of this agreement.', 8, true, '2026-03-05T13:50:34.727872+00:00'),
  ('35a75252-f580-47f1-aac4-345999f57cd9', 'Promotional Rights', 'Cooper Cricket reserves the right to use the player''s name, likeness, and playing statistics in promotional materials.', 9, true, '2026-03-05T13:50:34.727872+00:00'),
  ('80ea5a7f-96ec-433b-a619-1153fe5ab0b6', 'Promotional Events', 'Player will make themselves available for a minimum of two (2) promotional events per year as arranged by Cooper Cricket.', 10, true, '2026-03-05T13:50:34.727872+00:00'),
  ('f03c0bec-37b7-4940-b6f0-3db850ab76e0', 'Equipment Replacement', 'Equipment will be replaced on a like-for-like basis due to normal wear and tear at no additional cost to the player.', 11, true, '2026-03-05T13:50:34.727872+00:00'),
  ('e9af4cff-8fc6-41b8-881b-1d3d372a38df', 'Termination', 'This agreement may be terminated by either party with 30 days written notice.', 12, true, '2026-03-05T13:50:34.727872+00:00'),
  ('aca10fdd-872d-49e7-94bb-aae81ba8bd97', 'Dispute Resolution', 'Any disputes arising from this agreement will be resolved through mediation before pursuing legal action.', 13, true, '2026-03-05T13:50:34.727872+00:00'),
  ('72b9db0a-bc75-4162-a4ad-6918944c682e', 'Event Attendance Notice', 'Player must provide reasonable notice if unable to attend scheduled promotional events.', 14, true, '2026-03-05T13:50:34.727872+00:00')
