-- Full catalog import from the original Lovable database (project zfjcuzbpawnprzjofovm).
-- Replaces 20260513000000_seed_baseline.sql.
-- Idempotent: ON CONFLICT (id) DO UPDATE so re-running keeps the catalog in sync.

-- Wipe placeholder seed first to avoid duplicate names with different UUIDs.
-- (Categories/products inserted by my earlier placeholder seed had different IDs.)
DELETE FROM public.spec_options WHERE spec_type_id IN (SELECT id FROM public.spec_types WHERE key IN ('grade','handle','size'));
DELETE FROM public.spec_types WHERE key IN ('grade','handle','size');
DELETE FROM public.products WHERE name IN ('Cooper Pro Bat','Cooper Elite Bat','Cooper Test Pads','Cooper Pro Gloves','Cooper Pro Helmet','Cooper Tour Bag');
DELETE FROM public.categories WHERE name IN ('Bats','Pads','Gloves','Helmets','Bags') AND id NOT IN ('91f05896-cbb0-4a74-99d6-79d309b18908','58466142-b8f0-4562-a3d4-74fd86549116','1c555fdd-e7a1-470e-9c9c-2def7722ea81','ab0a1f36-fc9d-4679-ad4d-ae24463b55bc');
DELETE FROM public.colour_options WHERE value IN ('White','Black','Navy','Maroon');
DELETE FROM public.standard_terms WHERE title IN ('Exclusivity','Social Media Obligations','Brand Representation','Termination') AND id NOT IN (SELECT id FROM public.standard_terms WHERE title='Exclusivity' AND created_at::date='2026-03-05');

-- Categories
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, sort_order = EXCLUDED.sort_order, has_customisation = EXCLUDED.has_customisation, has_colour_variants = EXCLUDED.has_colour_variants;

-- Products
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, category_id = EXCLUDED.category_id, default_price = EXCLUDED.default_price, sort_order = EXCLUDED.sort_order, is_active = EXCLUDED.is_active;

-- Spec types
ON CONFLICT (id) DO UPDATE SET key = EXCLUDED.key, label = EXCLUDED.label, has_pricing = EXCLUDED.has_pricing, sort_order = EXCLUDED.sort_order, is_active = EXCLUDED.is_active;

-- Spec options
ON CONFLICT (id) DO UPDATE SET spec_type_id = EXCLUDED.spec_type_id, value = EXCLUDED.value, price = EXCLUDED.price, sort_order = EXCLUDED.sort_order, is_active = EXCLUDED.is_active;

-- Colour options
ON CONFLICT (id) DO UPDATE SET value = EXCLUDED.value, sort_order = EXCLUDED.sort_order, is_active = EXCLUDED.is_active;

-- Standard terms
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, body = EXCLUDED.body, sort_order = EXCLUDED.sort_order, is_active = EXCLUDED.is_active;
